import React from 'react'
import { Link, Outlet, useParams } from 'react-router-dom'

// useParams → reads dynamic segments from the URL
// e.g. /profile/himanshu  →  urldata.username === "himanshu"

function Profile() {
    const urldata = useParams()
  return (
    <div>
      <h2>Profile Screen</h2>
      welcome {urldata.username}
      following: 123

      <nav style={{ display:"flex", gap:"20px" }}>
        <Link to="/profile/photos">photos</Link>
        <Link to="/profile/reels">reels</Link>
      </nav>

      {/* Outlet → placeholder where nested route components (Photos / Reels) will render */}
      {/* without Outlet, nested routes are defined but never shown */}
      
      <Outlet />
    </div>
  )
}

export default Profile
